import{_ as d,C as c,o as s,c as u,j as t,a,b as i,w as n,E as r,a3 as l,a2 as p}from"./chunks/framework.B72_uj9U.js";const C=JSON.parse('{"title":"Multi-Agent Context Management","description":"","frontmatter":{},"headers":[],"relativePath":"research/concepts/context-management/multi-agent-context.md","filePath":"research/concepts/context-management/multi-agent-context.md"}'),g={name:"research/concepts/context-management/multi-agent-context.md"};function h(m,e,f,b,y,A){const o=c("Mermaid");return s(),u("div",null,[e[12]||(e[12]=t("h1",{id:"multi-agent-context-management",tabindex:"-1"},[a("Multi-Agent Context Management "),t("a",{class:"header-anchor",href:"#multi-agent-context-management","aria-label":'Permalink to "Multi-Agent Context Management"'},"​")],-1)),e[13]||(e[13]=t("h2",{id:"_1-introduction",tabindex:"-1"},[a("1. Introduction "),t("a",{class:"header-anchor",href:"#_1-introduction","aria-label":'Permalink to "1. Introduction"'},"​")],-1)),e[14]||(e[14]=t("p",null,[a("The fundamental insight behind multi-agent context management is deceptively simple: instead of trying to compress everything into a single context window, "),t("strong",null,"partition the work across multiple independent context windows"),a(".")],-1)),e[15]||(e[15]=t("p",null,'Every strategy we have examined so far — sliding windows, summarization, RAG retrieval, hierarchical memory — operates within the constraint of a single context window. They all ask the same question: "How do we fit more into less?" Multi-agent systems ask a different question entirely: "Why fit everything into one window at all?"',-1)),e[16]||(e[16]=t("p",null,"The architecture works like this:",-1)),(s(),i(l,null,{default:n(()=>[r(o,{id:"mermaid-15",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20Orch%5B%22**ORCHESTRATOR%20AGENT**%5Cn(maintains%20high-level%20state)%22%5D%0A%20%20%20%20WA%5B%22Worker%20A%5Cn128K%20ctx%20(fresh)%22%5D%0A%20%20%20%20WB%5B%22Worker%20B%5Cn128K%20ctx%20(fresh)%22%5D%0A%20%20%20%20WC%5B%22Worker%20C%5Cn128K%20ctx%20(fresh)%22%5D%0A%20%20%20%20Agg%5B%22Aggregated%20results%5Cn(few%20hundred%20tokens%20each)%22%5D%0A%20%20%20%20Orch%20--%3E%7C%22spawn%22%7C%20WA%0A%20%20%20%20Orch%20--%3E%7C%22spawn%22%7C%20WB%0A%20%20%20%20Orch%20--%3E%7C%22spawn%22%7C%20WC%0A%20%20%20%20WA%20--%3E%7C%22summary%20A%22%7C%20Agg%0A%20%20%20%20WB%20--%3E%7C%22summary%20B%22%7C%20Agg%0A%20%20%20%20WC%20--%3E%7C%22summary%20C%22%7C%20Agg%0A"})]),fallback:n(()=>[...e[0]||(e[0]=[a(" Loading... ",-1)])]),_:1})),e[17]||(e[17]=p(`<p>Each sub-agent gets its own <strong>fresh</strong> context window. It can consume 50K, 80K, even 100K tokens of file contents, search results, and analysis — and when it finishes, all of that is discarded. Only the distilled summary crosses the boundary back to the orchestrator.</p><p>The effective total context available to the system becomes the <strong>sum of all agent windows</strong>, not the size of any single one. A system with 5 agents each having 128K context effectively operates with 640K tokens of working memory — while each individual agent maintains clean, focused context.</p><p>This is arguably the most powerful context management strategy available today.</p><hr><h2 id="_2-the-orchestrator-knows-all-workers-know-little-pattern" tabindex="-1">2. The &quot;Orchestrator Knows All, Workers Know Little&quot; Pattern <a class="header-anchor" href="#_2-the-orchestrator-knows-all-workers-know-little-pattern" aria-label="Permalink to &quot;2. The &quot;Orchestrator Knows All, Workers Know Little&quot; Pattern&quot;">​</a></h2><p>The core organizational pattern in multi-agent context management is asymmetric knowledge distribution:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Orchestrator Knowledge:</span></span>
<span class="line"><span>  ✓ Full conversation history with user</span></span>
<span class="line"><span>  ✓ High-level task understanding</span></span>
<span class="line"><span>  ✓ Summaries from all previous worker outputs</span></span>
<span class="line"><span>  ✓ Global state and progress tracking</span></span>
<span class="line"><span>  ✗ Raw file contents (delegated to workers)</span></span>
<span class="line"><span>  ✗ Detailed exploration results (only summaries)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Worker Knowledge:</span></span>
<span class="line"><span>  ✓ Specific task description (a few sentences)</span></span>
<span class="line"><span>  ✓ Relevant file paths or search queries</span></span>
<span class="line"><span>  ✓ Minimal necessary context from orchestrator</span></span>
<span class="line"><span>  ✗ Full conversation history</span></span>
<span class="line"><span>  ✗ Other workers&#39; results</span></span>
<span class="line"><span>  ✗ Global state or progress</span></span>
<span class="line"><span>  ✗ Why this task matters in the broader picture</span></span></code></pre></div><p>Workers receive <strong>minimal context</strong>: just their specific task plus whatever files or information they need to complete it. They do not see the full conversation history, they do not see other workers&#39; results, and they do not know the global state of the system.</p><p><strong>Benefits:</strong></p><ul><li>Each worker operates with clean, focused context — no irrelevant noise</li><li>Total effective context equals the sum of all windows</li><li>Workers can be parallelized (independent contexts mean no conflicts)</li><li>Failed workers can be retried without polluting the orchestrator&#39;s context</li></ul><p><strong>Drawbacks:</strong></p><ul><li>Communication overhead: every spawn costs tokens for task description</li><li>Information loss at boundaries: summaries inevitably discard details</li><li>Coordination complexity: the orchestrator must track what each worker knows</li><li>Latency: sequential worker chains add round-trip time per stage</li></ul><p>The quality of this pattern depends almost entirely on how well the orchestrator formulates task descriptions and how effectively it synthesizes worker outputs.</p><hr><h2 id="_3-claude-code-s-sub-agent-architecture" tabindex="-1">3. Claude Code&#39;s Sub-Agent Architecture <a class="header-anchor" href="#_3-claude-code-s-sub-agent-architecture" aria-label="Permalink to &quot;3. Claude Code&#39;s Sub-Agent Architecture&quot;">​</a></h2><p>Claude Code&#39;s documentation is explicit about its philosophy:</p><blockquote><p>&quot;Sub-agents are the most powerful context management tool.&quot;</p></blockquote><p>The architecture is built around a single principle: <strong>expensive exploration should never happen in the main context window</strong>. Instead, exploration is delegated to sub-agents that operate in separate context windows.</p>`,18)),(s(),i(l,null,{default:n(()=>[r(o,{id:"mermaid-104",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20Main%5B%22**Main%20Context%20Window**%5CnYour%20conversation%20(preserved)%5Cn%2B%20compact%20summary%22%5D%0A%20%20%20%20Sub%5B%22**Sub-Agent%20Context%20Window**%5CnExploration%20task%5CnReads%20files%2C%20searches%20codebase%5CnAnalyzes%20patterns%5Cn(all%20discarded%20after)%22%5D%0A%20%20%20%20Main%20--%3E%7C%22spawn%22%7C%20Sub%0A%20%20%20%20Sub%20--%3E%7C%22summary%22%7C%20Main%0A"})]),fallback:n(()=>[...e[1]||(e[1]=[a(" Loading... ",-1)])]),_:1})),e[18]||(e[18]=p(`<p>The key insight is quantitative. Consider what happens when you explore a codebase directly in the main context:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Direct exploration in main context:</span></span>
<span class="line"><span>  Read file 1:   3,000 tokens  →  cumulative: 3,000</span></span>
<span class="line"><span>  Read file 2:   2,500 tokens  →  cumulative: 5,500</span></span>
<span class="line"><span>  Read file 3:   4,000 tokens  →  cumulative: 9,500</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span>  Read file 20:  2,000 tokens  →  cumulative: 50,000+</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  All 50K tokens remain in context for EVERY subsequent turn.</span></span>
<span class="line"><span>  Over 30 turns: 50K × 30 = 1.5M input tokens processed.</span></span></code></pre></div><p>Now consider the sub-agent approach:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Sub-agent exploration:</span></span>
<span class="line"><span>  Sub-agent reads 20 files:     50,000 tokens (consumed once)</span></span>
<span class="line"><span>  Sub-agent returns summary:       500 tokens (to main context)</span></span>
<span class="line"><span>  Sub-agent context discarded:  50,000 tokens freed</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Main context grows by only 500 tokens.</span></span>
<span class="line"><span>  Over 30 turns: 500 × 30 = 15K input tokens processed.</span></span>
<span class="line"><span>  Savings: ~1.485M tokens (99% reduction in carried context)</span></span></code></pre></div><p><strong>Use cases for sub-agent exploration:</strong></p><ul><li>Codebase exploration: &quot;Find all files related to authentication&quot;</li><li>Test analysis: &quot;What test patterns does this project use?&quot;</li><li>Documentation search: &quot;How is the API versioned?&quot;</li><li>Dependency analysis: &quot;What depends on this module?&quot;</li></ul><p><strong>Cost of sub-agent spawning:</strong></p><ul><li>Task description to sub-agent: ~500 tokens</li><li>Sub-agent&#39;s own processing: ~50K tokens (but in isolated context)</li><li>Summary returned: ~500 tokens</li><li>Total main context cost: ~1,000 tokens</li></ul><p><strong>Compared to direct exploration:</strong></p><ul><li>20+ tool calls filling main context: ~50K tokens permanently added</li><li>Each subsequent turn re-processes those 50K tokens</li><li>Break-even point: sub-agent spawning saves tokens after just 2 turns</li></ul><p>Claude Code uses different sub-agent types optimized for different tasks:</p><ul><li><strong>Explore agents</strong>: lightweight, fast model, read-only (safe to parallelize)</li><li><strong>Task agents</strong>: heavier, can execute commands, returns brief success/failure</li><li><strong>General-purpose agents</strong>: full capability, separate context window</li></ul><p>The critical design choice: explore agents use a cheaper, faster model (Haiku-class) because their job is information gathering, not complex reasoning. This makes sub-agent spawning both token-efficient and cost-efficient.</p><hr><h2 id="_4-forgecode-s-three-agent-pipeline" tabindex="-1">4. ForgeCode&#39;s Three-Agent Pipeline <a class="header-anchor" href="#_4-forgecode-s-three-agent-pipeline" aria-label="Permalink to &quot;4. ForgeCode&#39;s Three-Agent Pipeline&quot;">​</a></h2><p>ForgeCode implements a strict three-stage pipeline where each agent receives only the distilled output of the previous stage:</p>`,16)),(s(),i(l,null,{default:n(()=>[r(o,{id:"mermaid-213",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20Sage%5B%22**Stage%201%3A%20SAGE%20(Understanding)**%5CnInput%3A%20User%20request%20%2B%20codebase%5CnProcess%3A%20Semantic%20entry-point%20search%2C%5Cndependency%20graph%20traversal%2C%20pattern%20recognition%5CnOutput%3A%20Relevant%20files%2C%20architecture%20patterns%2C%20dependencies%22%5D%0A%20%20%20%20Muse%5B%22**Stage%202%3A%20MUSE%20(Planning)**%5CnInput%3A%20Sage's%20understanding%5CnProcess%3A%20Change%20planning%2C%20impact%20analysis%2C%5Cnconflict%20resolution%5CnOutput%3A%20Files%20to%20modify%2C%20exact%20changes%2C%20order%20of%20operations%22%5D%0A%20%20%20%20Forge%5B%22**Stage%203%3A%20FORGE%20(Execution)**%5CnInput%3A%20Muse's%20change%20plan%5CnProcess%3A%20Code%20modification%2C%20test%20execution%2C%20validation%5CnOutput%3A%20Modified%20codebase%22%5D%0A%20%20%20%20Sage%20--%3E%7C%22distilled%20understanding%2C%20NOT%20raw%20files%22%7C%20Muse%0A%20%20%20%20Muse%20--%3E%7C%22refined%20plan%2C%20NOT%20exploration%20context%22%7C%20Forge%0A"})]),fallback:n(()=>[...e[2]||(e[2]=[a(" Loading... ",-1)])]),_:1})),e[19]||(e[19]=p('<p>Each stage acts as a <strong>compression boundary</strong>. Sage might read 40 files and analyze thousands of lines of code, but Muse only receives a structured summary of what Sage found. Muse might consider dozens of possible change strategies, but Forge only receives the final plan.</p><p><strong>Semantic entry-point discovery</strong> is particularly interesting: before Sage even starts exploring, the system identifies the most relevant starting points in the codebase using semantic search. This narrows context before any agent begins processing, avoiding the &quot;read everything&quot; trap.</p><p>ForgeCode claims &quot;up to 93% fewer tokens&quot; compared to naive single-agent exploration. The math supports this: if a single agent would need to carry 100K tokens of context through a full task, a three-stage pipeline where each stage receives only ~7K tokens of distilled context achieves roughly that reduction.</p><p>The trade-off is rigidity. The pipeline is strictly sequential — you cannot go back from Forge to Sage if new information emerges during execution. Some systems address this with feedback loops, but ForgeCode opts for the simpler linear design.</p><hr><h2 id="_5-ante-s-meta-agent-sub-agent-distribution" tabindex="-1">5. Ante&#39;s Meta-Agent + Sub-Agent Distribution <a class="header-anchor" href="#_5-ante-s-meta-agent-sub-agent-distribution" aria-label="Permalink to &quot;5. Ante&#39;s Meta-Agent + Sub-Agent Distribution&quot;">​</a></h2><p>Ante takes a more dynamic approach to multi-agent coordination. Rather than a fixed pipeline, it uses a meta-agent that spawns sub-agents on demand based on the task requirements.</p>',7)),(s(),i(l,null,{default:n(()=>[r(o,{id:"mermaid-233",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20Meta%5B%22**META-AGENT**%5Cn(task%20understanding%20%2B%20coordination)%5CnAnalyzes%20task%20%E2%86%92%20Decides%20decomposition%22%5D%0A%20%20%20%20SA1%5B%22Sub-agent%3A%20Fix%20auth%20bug%22%5D%0A%20%20%20%20SA2%5B%22Sub-agent%3A%20Update%20tests%22%5D%0A%20%20%20%20SA3%5B%22Sub-agent%3A%20Update%20docs%22%5D%0A%20%20%20%20Synth%5B%22Collect%20results%20%E2%86%92%20Synthesize%22%5D%0A%20%20%20%20Meta%20--%3E%7C%22spawn%22%7C%20SA1%0A%20%20%20%20Meta%20--%3E%7C%22spawn%22%7C%20SA2%0A%20%20%20%20Meta%20--%3E%7C%22spawn%22%7C%20SA3%0A%20%20%20%20SA1%20--%3E%20Synth%0A%20%20%20%20SA2%20--%3E%20Synth%0A%20%20%20%20SA3%20--%3E%20Synth%0A"})]),fallback:n(()=>[...e[3]||(e[3]=[a(" Loading... ",-1)])]),_:1})),e[20]||(e[20]=p('<p><strong>Key characteristics:</strong></p><ul><li><strong>Dynamic spawning</strong>: the number and type of sub-agents is determined at runtime based on task complexity, not predefined</li><li><strong>Effective total context</strong>: if the meta-agent has 128K and spawns 4 sub-agents each with 128K, the system has 640K tokens of working memory</li><li><strong>Result aggregation</strong>: the meta-agent collects outputs from all sub-agents and synthesizes a coherent result</li><li><strong>Failure isolation</strong>: if one sub-agent fails, the meta-agent can retry it without affecting others</li></ul><p>The meta-agent maintains a lightweight representation of the overall task state — which sub-tasks are complete, which are pending, what dependencies exist. Sub-agents are stateless from the meta-agent&#39;s perspective: they receive a task, produce a result, and their context is discarded.</p><p>This architecture scales naturally. A simple task might need one sub-agent. A complex refactoring might spawn a dozen. The meta-agent&#39;s context grows only by the size of each sub-agent&#39;s summary, not by the raw exploration each performed.</p><hr><h2 id="_6-capy-s-spec-document-boundary" tabindex="-1">6. Capy&#39;s Spec Document Boundary <a class="header-anchor" href="#_6-capy-s-spec-document-boundary" aria-label="Permalink to &quot;6. Capy&#39;s Spec Document Boundary&quot;">​</a></h2><p>Capy implements a two-agent system with a particularly clean compression boundary: a structured specification document.</p>',7)),(s(),i(l,null,{default:n(()=>[r(o,{id:"mermaid-272",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20Cap%5B%22**Phase%201%3A%20CAPTAIN%20(Exploration%20%2B%20Planning)**%5CnExplores%20codebase%20extensively%5CnGathers%20all%20relevant%20information%5CnUnderstands%20dependencies%5CnIdentifies%20constraints%22%5D%0A%20%20%20%20Spec%5B%22**STRUCTURED%20SPEC%20DOCUMENT**%5Cn%23%23%20Files%20to%20Modify%5Cn-%20src%2Fauth.ts%3A%20add%20OAuth%20flow%5Cn-%20src%2Froutes.ts%3A%20new%20endpoint%5Cn%23%23%20Specific%20Changes%5Cn%23%23%20Dependencies%5Cn%23%23%20Test%20Requirements%22%5D%0A%20%20%20%20Build%5B%22**Phase%202%3A%20BUILD%20(Execution)**%5CnInput%3A%20Spec%20document%20%2B%20codebase%5CnFollows%20spec%20precisely%5CnReads%20only%20files%20mentioned%20in%20spec%5CnRuns%20tests%20as%20required%22%5D%0A%20%20%20%20Cap%20--%3E%20Spec%0A%20%20%20%20Spec%20--%3E%7C%22spec%20document%20only%22%7C%20Build%0A"})]),fallback:n(()=>[...e[4]||(e[4]=[a(" Loading... ",-1)])]),_:1})),e[21]||(e[21]=p('<p>The spec document serves as a <strong>&quot;lossless summary&quot;</strong> — more structured than a free-form summary, with explicit sections for different types of information. This structure makes it harder to accidentally omit critical details.</p><p><strong>What goes in the spec:</strong></p><ul><li>Files to modify and the rationale for each change</li><li>Specific changes needed (as precise as possible)</li><li>Dependencies and ordering constraints</li><li>Test requirements and acceptance criteria</li><li>Warnings about fragile areas or edge cases</li></ul><p><strong>Why a spec document beats a free-form summary:</strong></p><ul><li>Structure forces completeness (empty sections are visible)</li><li>Build agent can reference specific sections</li><li>Easier to validate before handing off</li><li>Acts as documentation of the change plan</li></ul><p>The Build agent starts with a <strong>completely clean context</strong> — no exploration history, no false starts, no abandoned approaches. It sees only the spec and the codebase. This means its entire context budget is available for the actual work of making changes, not for understanding what changes to make.</p><hr><h2 id="_7-tongagents-multi-agent-framework" tabindex="-1">7. TongAgents&#39; Multi-Agent Framework <a class="header-anchor" href="#_7-tongagents-multi-agent-framework" aria-label="Permalink to &quot;7. TongAgents&#39; Multi-Agent Framework&quot;">​</a></h2><p>TongAgents takes multi-agent architecture in a different direction: rather than a fixed pipeline or orchestrator pattern, it uses multiple specialized agents that collaborate on tasks based on their individual capabilities.</p><p><strong>Key design principles:</strong></p><ul><li><strong>Role specialization</strong>: each agent has a defined role (code reader, test writer, refactoring expert) with corresponding system prompts and tool access</li><li><strong>Task decomposition</strong>: complex tasks are broken into subtasks matched to agent specializations</li><li><strong>Proportional complexity</strong>: simple subtasks get simple agents (shorter prompts, fewer tools), complex subtasks get more capable agents</li><li><strong>Shared state boundaries</strong>: agents communicate through defined output formats, not raw context sharing</li></ul>',11)),(s(),i(l,null,{default:n(()=>[r(o,{id:"mermaid-366",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20CA%5B%22**Code%20Analyzer**%5CnReads%20code%5CnFinds%20dependencies%5CnMaps%20types%22%5D%0A%20%20%20%20AA%5B%22**Architect%20Agent**%5CnPlans%20new%20structure%5CnDefines%20interfaces%22%5D%0A%20%20%20%20RA%5B%22**Refactor%20Agent**%5CnExecutes%20changes%5CnMoves%20code%22%5D%0A%20%20%20%20TA%5B%22**Test%20Agent**%5CnValidates%20behavior%5CnRuns%20tests%22%5D%0A%20%20%20%20Out%5B%22Shared%20output%20format%22%5D%0A%20%20%20%20CA%20--%3E%20Out%0A%20%20%20%20AA%20--%3E%20Out%0A%20%20%20%20RA%20--%3E%20Out%0A%20%20%20%20TA%20--%3E%20Out%0A"})]),fallback:n(()=>[...e[5]||(e[5]=[a(" Loading... ",-1)])]),_:1})),e[22]||(e[22]=t("p",null,[a("The important context management insight from TongAgents is "),t("strong",null,"proportional resource allocation"),a(": not every subtask needs a full 128K context window with an expensive model. A simple file-reading task can use a smaller, faster agent with minimal context, while a complex architectural decision gets a more capable agent with richer context.")],-1)),e[23]||(e[23]=t("hr",null,null,-1)),e[24]||(e[24]=t("h2",{id:"_8-context-handoff-patterns",tabindex:"-1"},[a("8. Context Handoff Patterns "),t("a",{class:"header-anchor",href:"#_8-context-handoff-patterns","aria-label":'Permalink to "8. Context Handoff Patterns"'},"​")],-1)),e[25]||(e[25]=t("p",null,"How context moves between agents is the defining characteristic of any multi-agent system. Four primary patterns emerge across the tools we have studied:",-1)),e[26]||(e[26]=t("h3",{id:"_8-1-summary-handoff",tabindex:"-1"},[a("8.1 Summary Handoff "),t("a",{class:"header-anchor",href:"#_8-1-summary-handoff","aria-label":'Permalink to "8.1 Summary Handoff"'},"​")],-1)),e[27]||(e[27]=t("p",null,"The simplest and most common pattern. Agent A completes its work and produces a natural-language summary. Agent B receives this summary as part of its initial prompt.",-1)),(s(),i(l,null,{default:n(()=>[r(o,{id:"mermaid-383",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22**Agent%20A**%5CnDoes%20work%5Cn(50K%20ctx)%22%5D%20--%3E%7C%22text%20summary%5Cn(500%20tokens)%22%7C%20B%5B%22**Agent%20B**%5CnReceives%20summary%22%5D%0A"})]),fallback:n(()=>[...e[6]||(e[6]=[a(" Loading... ",-1)])]),_:1})),e[28]||(e[28]=t("p",null,[t("strong",null,"Used by:"),a(" Claude Code sub-agents, most exploration patterns "),t("strong",null,"Strength:"),a(" Simple, flexible, works with any agent "),t("strong",null,"Weakness:"),a(" Summary quality is the bottleneck — critical details can be lost "),t("strong",null,"Risk:"),a(" The summarizing agent might not know what will be important to Agent B")],-1)),e[29]||(e[29]=t("h3",{id:"_8-2-structured-handoff",tabindex:"-1"},[a("8.2 Structured Handoff "),t("a",{class:"header-anchor",href:"#_8-2-structured-handoff","aria-label":'Permalink to "8.2 Structured Handoff"'},"​")],-1)),e[30]||(e[30]=t("p",null,"Agent A produces a structured document (spec, plan, JSON schema) rather than free-form text. Agent B parses and follows the structure.",-1)),(s(),i(l,null,{default:n(()=>[r(o,{id:"mermaid-393",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22**Agent%20A**%5CnDoes%20work%5Cn(50K%20ctx)%22%5D%20--%3E%7C%22structured%20spec%2Fplan%5Cn(2K%20tokens)%22%7C%20B%5B%22**Agent%20B**%5CnFollows%20spec%22%5D%0A"})]),fallback:n(()=>[...e[7]||(e[7]=[a(" Loading... ",-1)])]),_:1})),e[31]||(e[31]=t("p",null,[t("strong",null,"Used by:"),a(" Capy (spec document), ForgeCode (change plans) "),t("strong",null,"Strength:"),a(" More reliable, forces completeness, acts as documentation "),t("strong",null,"Weakness:"),a(" Requires predefined structure, less flexible "),t("strong",null,"Risk:"),a(" Rigid structure may not capture all task types well")],-1)),e[32]||(e[32]=t("h3",{id:"_8-3-shared-state-handoff",tabindex:"-1"},[a("8.3 Shared State Handoff "),t("a",{class:"header-anchor",href:"#_8-3-shared-state-handoff","aria-label":'Permalink to "8.3 Shared State Handoff"'},"​")],-1)),e[33]||(e[33]=t("p",null,"Agents do not directly pass context to each other. Instead, they communicate through a shared external state — a file system, database, or event log.",-1)),(s(),i(l,null,{default:n(()=>[r(o,{id:"mermaid-403",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22**Agent%20A**%5CnWrites%20results%22%5D%20--%3E%7C%22write%22%7C%20SS%5B%22**Shared%20State**%5CnFile%20system%5CnDatabase%5CnEvent%20stream%22%5D%0A%20%20%20%20SS%20--%3E%7C%22read%22%7C%20B%5B%22**Agent%20B**%5CnReads%20results%22%5D%0A"})]),fallback:n(()=>[...e[8]||(e[8]=[a(" Loading... ",-1)])]),_:1})),e[34]||(e[34]=t("p",null,[t("strong",null,"Used by:"),a(" OpenHands (EventStream), most file-system-based tools "),t("strong",null,"Strength:"),a(" Loose coupling, agents don't need to know about each other "),t("strong",null,"Weakness:"),a(" Implicit communication is harder to debug and reason about "),t("strong",null,"Risk:"),a(" Race conditions, stale reads, ordering issues")],-1)),e[35]||(e[35]=t("h3",{id:"_8-4-progressive-refinement",tabindex:"-1"},[a("8.4 Progressive Refinement "),t("a",{class:"header-anchor",href:"#_8-4-progressive-refinement","aria-label":'Permalink to "8.4 Progressive Refinement"'},"​")],-1)),e[36]||(e[36]=t("p",null,"Each agent in a pipeline takes the previous agent's output and refines it further. Context narrows at each stage — from broad understanding to specific plan to concrete execution.",-1)),(s(),i(l,null,{default:n(()=>[r(o,{id:"mermaid-413",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22**Agent%20A**%5CnBroad%20analysis%5Cn(wide%20context)%22%5D%20--%3E%7C%22output%22%7C%20B%5B%22**Agent%20B**%5CnRefined%20planning%5Cn(narrower%20context)%22%5D%0A%20%20%20%20B%20--%3E%7C%22output%22%7C%20C%5B%22**Agent%20C**%5CnSpecific%20execution%5Cn(focused%20context)%22%5D%0A"})]),fallback:n(()=>[...e[9]||(e[9]=[a(" Loading... ",-1)])]),_:1})),e[37]||(e[37]=p('<p>Context breadth narrows at each stage.</p><p><strong>Used by:</strong> ForgeCode (Sage → Muse → Forge) <strong>Strength:</strong> Natural compression at each stage, clear separation of concerns <strong>Weakness:</strong> Strictly sequential, no backtracking without full restart <strong>Risk:</strong> Early-stage errors propagate and amplify through the pipeline</p><hr><h2 id="_9-shared-state-vs-isolated-state-patterns" tabindex="-1">9. Shared State vs. Isolated State Patterns <a class="header-anchor" href="#_9-shared-state-vs-isolated-state-patterns" aria-label="Permalink to &quot;9. Shared State vs. Isolated State Patterns&quot;">​</a></h2><h3 id="_9-1-fully-isolated" tabindex="-1">9.1 Fully Isolated <a class="header-anchor" href="#_9-1-fully-isolated" aria-label="Permalink to &quot;9.1 Fully Isolated&quot;">​</a></h3><p>Each agent has completely independent context. No shared memory, no shared files, no implicit communication. All information transfer is explicit through messages or summaries.</p><p><strong>Pros:</strong> Clean contexts, no cross-contamination, easy to reason about, trivially parallelizable <strong>Cons:</strong> Information loss at every boundary, high coordination overhead <strong>Example:</strong> Claude Code&#39;s explore sub-agents — they receive a task, return a summary, and their context is completely discarded</p><h3 id="_9-2-shared-file-system" tabindex="-1">9.2 Shared File System <a class="header-anchor" href="#_9-2-shared-file-system" aria-label="Permalink to &quot;9.2 Shared File System&quot;">​</a></h3><p>Agents share access to the same codebase and file system. They read source files directly and write their outputs (code changes, test files) to the shared file system. Communication happens implicitly through file modifications.</p><p><strong>Pros:</strong> Natural for coding tasks, agents can see each other&#39;s changes, no explicit serialization needed <strong>Cons:</strong> Ordering matters (Agent B must wait for Agent A to finish writing), merge conflicts possible, harder to isolate failures <strong>Example:</strong> Nearly all multi-agent coding tools — the codebase is inherently shared</p><h3 id="_9-3-shared-database" tabindex="-1">9.3 Shared Database <a class="header-anchor" href="#_9-3-shared-database" aria-label="Permalink to &quot;9.3 Shared Database&quot;">​</a></h3><p>Agents share a structured database for coordination. More organized than a file system, enables queries across agent outputs, supports transactions.</p><p><strong>Pros:</strong> Structured queries, ACID properties, natural for tracking state <strong>Cons:</strong> Schema design overhead, not natural for all tasks <strong>Example:</strong> Task tracking databases, build status coordination, test result aggregation</p><h3 id="_9-4-event-stream" tabindex="-1">9.4 Event Stream <a class="header-anchor" href="#_9-4-event-stream" aria-label="Permalink to &quot;9.4 Event Stream&quot;">​</a></h3><p>A shared append-only log of events that all agents can read. Each agent subscribes to relevant event types and publishes its own events. Enables loose coupling — agents do not need to know about each other, only about event types.</p>',15)),(s(),i(l,null,{default:n(()=>[r(o,{id:"mermaid-457",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20ES%5B%22**EVENT%20STREAM**%5Cn%5BFileRead%3A%20auth.ts%5D%5Cn%5BAnalysis%3A%20'auth%20uses%20JWT'%5D%5Cn%5BPlanCreated%3A%20%7Bchanges%3A%20%5B...%5D%7D%5D%5Cn%5BFileModified%3A%20auth.ts%5D%5Cn%5BTestRun%3A%20%7Bpassed%3A%2015%2C%20failed%3A%200%7D%5D%5Cn%5BTaskComplete%3A%20'auth%20refactoring%20done'%5D%22%5D%0A%20%20%20%20AgA%5B%22Agent%20A%5Cn(explorer)%22%5D%0A%20%20%20%20AgB%5B%22Agent%20B%5Cn(modifier)%22%5D%0A%20%20%20%20AgC%5B%22Agent%20C%5Cn(tester)%22%5D%0A%20%20%20%20AgA%20--%3E%7C%22publish%20%2F%20subscribe%22%7C%20ES%0A%20%20%20%20AgB%20--%3E%7C%22publish%20%2F%20subscribe%22%7C%20ES%0A%20%20%20%20AgC%20--%3E%7C%22publish%20%2F%20subscribe%22%7C%20ES%0A"})]),fallback:n(()=>[...e[10]||(e[10]=[a(" Loading... ",-1)])]),_:1})),e[38]||(e[38]=p(`<p><strong>Pros:</strong> Loose coupling, full audit trail, enables replay, agents can join/leave <strong>Cons:</strong> Agents must filter relevant events (context management within the stream), ordering and consistency challenges <strong>Example:</strong> OpenHands&#39; EventStream architecture</p><hr><h2 id="_10-token-savings-from-multi-agent-architecture" tabindex="-1">10. Token Savings from Multi-Agent Architecture <a class="header-anchor" href="#_10-token-savings-from-multi-agent-architecture" aria-label="Permalink to &quot;10. Token Savings from Multi-Agent Architecture&quot;">​</a></h2><p>The token economics of multi-agent systems reveal why this pattern is so compelling.</p><h3 id="single-agent-scenario" tabindex="-1">Single-Agent Scenario <a class="header-anchor" href="#single-agent-scenario" aria-label="Permalink to &quot;Single-Agent Scenario&quot;">​</a></h3><p>A coding task requires exploring 20 files (averaging 2,500 tokens each = 50,000 tokens total). The task takes 30 turns to complete.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Turn  1: Read 20 files          →  context: 50,000 tokens</span></span>
<span class="line"><span>Turn  2: Analyze + plan         →  context: 52,000 tokens</span></span>
<span class="line"><span>Turn  3: Edit file 1            →  context: 54,000 tokens</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>Turn 30: Final validation       →  context: 80,000 tokens</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Total input tokens processed across all turns:</span></span>
<span class="line"><span>  50K + 52K + 54K + ... + 80K ≈ 1,950,000 tokens</span></span>
<span class="line"><span>  (every turn re-reads all previous context)</span></span></code></pre></div><h3 id="multi-agent-scenario" tabindex="-1">Multi-Agent Scenario <a class="header-anchor" href="#multi-agent-scenario" aria-label="Permalink to &quot;Multi-Agent Scenario&quot;">​</a></h3><p>An orchestrator spawns a sub-agent for exploration. The sub-agent reads the 20 files, analyzes them, and returns a 500-token summary. The orchestrator then proceeds with the 30-turn task using only the summary.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Sub-agent (1 turn):</span></span>
<span class="line"><span>  Read 20 files + analyze       →  context: 55,000 tokens</span></span>
<span class="line"><span>  Return summary                →  500 tokens to orchestrator</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Orchestrator:</span></span>
<span class="line"><span>  Turn  1: Receive summary      →  context: 2,500 tokens</span></span>
<span class="line"><span>  Turn  2: Plan from summary    →  context: 4,500 tokens</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span>  Turn 29: Final validation     →  context: 32,000 tokens</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Total input tokens processed:</span></span>
<span class="line"><span>  Sub-agent: 55,000 (one-time cost)</span></span>
<span class="line"><span>  Orchestrator: 2.5K + 4.5K + ... + 32K ≈ 500,000 tokens</span></span>
<span class="line"><span>  Total: ~555,000 tokens</span></span></code></pre></div><h3 id="savings-summary" tabindex="-1">Savings Summary <a class="header-anchor" href="#savings-summary" aria-label="Permalink to &quot;Savings Summary&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────┬─────────────┬──────────────┬──────────┐</span></span>
<span class="line"><span>│ Metric             │ Single-Agent│ Multi-Agent   │ Savings  │</span></span>
<span class="line"><span>├────────────────────┼─────────────┼──────────────┼──────────┤</span></span>
<span class="line"><span>│ Exploration cost   │ 50K (kept)  │ 55K (discard) │ -5K     │</span></span>
<span class="line"><span>│ Per-turn overhead  │ +50K/turn   │ +500/turn     │ 49.5K   │</span></span>
<span class="line"><span>│ Total (30 turns)   │ ~1,950K     │ ~555K         │ ~71%    │</span></span>
<span class="line"><span>│ Peak context       │ 80K         │ 32K           │ 60%     │</span></span>
<span class="line"><span>└────────────────────┴─────────────┴──────────────┴──────────┘</span></span></code></pre></div><h3 id="scaling-with-task-complexity" tabindex="-1">Scaling with Task Complexity <a class="header-anchor" href="#scaling-with-task-complexity" aria-label="Permalink to &quot;Scaling with Task Complexity&quot;">​</a></h3><p>The savings amplify as tasks become more complex:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────┬────────────┬─────────────┬──────────────┐</span></span>
<span class="line"><span>│ Task Complexity  │ Files Read │ Task Turns  │ Token Savings │</span></span>
<span class="line"><span>├──────────────────┼────────────┼─────────────┼──────────────┤</span></span>
<span class="line"><span>│ Simple (bug fix) │ 5          │ 10          │ ~45%         │</span></span>
<span class="line"><span>│ Medium (feature) │ 20         │ 30          │ ~71%         │</span></span>
<span class="line"><span>│ Large (refactor) │ 50         │ 60          │ ~85%         │</span></span>
<span class="line"><span>│ Massive (rewrite)│ 100+       │ 100+        │ ~93%         │</span></span>
<span class="line"><span>└──────────────────┴────────────┴─────────────┴──────────────┘</span></span></code></pre></div><p>The pattern is clear: <strong>the more exploration a task requires, the more multi-agent architectures save</strong>. For massive tasks, the savings approach the theoretical maximum — essentially the ratio of summary size to raw exploration size.</p><h3 id="break-even-analysis" tabindex="-1">Break-Even Analysis <a class="header-anchor" href="#break-even-analysis" aria-label="Permalink to &quot;Break-Even Analysis&quot;">​</a></h3><p>Sub-agent spawning is not free. Each spawn costs:</p><ul><li>Task description to sub-agent: ~500 tokens</li><li>Sub-agent system prompt: ~2,000 tokens</li><li>Sub-agent processing: billed separately (but context is smaller)</li><li>Summary returned to orchestrator: ~500 tokens</li></ul><p>Total overhead per spawn: ~3,000-5,000 tokens in the orchestrator&#39;s context.</p><p>A sub-agent that reads 10 files (~25K tokens) and returns a 500-token summary saves ~24,500 tokens of carried context per subsequent turn. After just <strong>one additional turn</strong>, the spawn has paid for itself.</p><hr><h2 id="_11-challenges-and-trade-offs" tabindex="-1">11. Challenges and Trade-offs <a class="header-anchor" href="#_11-challenges-and-trade-offs" aria-label="Permalink to &quot;11. Challenges and Trade-offs&quot;">​</a></h2><h3 id="information-loss-at-boundaries" tabindex="-1">Information Loss at Boundaries <a class="header-anchor" href="#information-loss-at-boundaries" aria-label="Permalink to &quot;Information Loss at Boundaries&quot;">​</a></h3><p>The greatest risk of multi-agent systems is that summaries lose critical details. A sub-agent might explore 20 files and summarize: &quot;Authentication uses JWT tokens with 24-hour expiry.&quot; But the main agent might later need to know that the JWT signing key is loaded from an environment variable — a detail the summary omitted.</p><p><strong>Mitigation strategies:</strong></p><ul><li>Use structured summaries that force inclusion of specific detail categories</li><li>Allow the orchestrator to ask follow-up questions or spawn additional sub-agents</li><li>Include &quot;notable details&quot; sections in summaries for edge cases and gotchas</li><li>Let the orchestrator specify what details matter before spawning</li></ul><h3 id="coordination-overhead" tabindex="-1">Coordination Overhead <a class="header-anchor" href="#coordination-overhead" aria-label="Permalink to &quot;Coordination Overhead&quot;">​</a></h3><p>Every agent spawn requires tokens for:</p><ul><li>Formulating the task description</li><li>The sub-agent&#39;s system prompt and tool descriptions</li><li>Processing the returned summary</li><li>Deciding what to do with the results</li></ul><p>For trivial tasks, this overhead can exceed the work itself. Spawning a sub-agent to read a single short file is wasteful — just read it directly.</p><h3 id="latency" tabindex="-1">Latency <a class="header-anchor" href="#latency" aria-label="Permalink to &quot;Latency&quot;">​</a></h3><p>Multi-agent systems add latency at every boundary:</p><ul><li>Spawning a sub-agent: 1 LLM call to formulate the task</li><li>Sub-agent processing: N LLM calls for the sub-agent&#39;s work</li><li>Result processing: 1 LLM call to process the summary</li></ul><p>A three-stage pipeline like ForgeCode adds at least 3× the minimum latency compared to a single agent that starts working immediately. Sequential pipelines are especially affected; parallel spawning helps but only when subtasks are independent.</p><h3 id="debugging-complexity" tabindex="-1">Debugging Complexity <a class="header-anchor" href="#debugging-complexity" aria-label="Permalink to &quot;Debugging Complexity&quot;">​</a></h3><p>When something goes wrong in a multi-agent system, tracing the failure is harder:</p><ul><li>Which agent made the wrong decision?</li><li>Was the information lost in a handoff?</li><li>Did the orchestrator formulate the task poorly?</li><li>Did the sub-agent misunderstand the task?</li></ul><p>Each boundary is a potential failure point, and the discarded context of sub-agents makes post-hoc analysis difficult.</p><h3 id="when-not-to-use-multi-agent" tabindex="-1">When NOT to Use Multi-Agent <a class="header-anchor" href="#when-not-to-use-multi-agent" aria-label="Permalink to &quot;When NOT to Use Multi-Agent&quot;">​</a></h3><p>Multi-agent is not always the right answer:</p><ul><li><strong>Simple tasks</strong>: a one-file bug fix does not need agent coordination</li><li><strong>Short sessions</strong>: if the task completes in 5 turns, overhead exceeds savings</li><li><strong>Full-history tasks</strong>: some tasks genuinely require the full conversation context (e.g., iterating on a design with the user)</li><li><strong>Tightly coupled changes</strong>: when every part of the task depends on every other part, partitioning provides little benefit</li></ul><hr><h2 id="_12-design-principles" tabindex="-1">12. Design Principles <a class="header-anchor" href="#_12-design-principles" aria-label="Permalink to &quot;12. Design Principles&quot;">​</a></h2><p>Based on the patterns observed across all the systems studied, these principles emerge for effective multi-agent context management:</p><p><strong>1. Give each agent the MINIMUM context it needs.</strong> Do not pass &quot;everything just in case.&quot; Every extra token in an agent&#39;s context is a token that competes with the agent&#39;s actual work for attention and processing.</p><p><strong>2. Use structured handoffs over free-form summaries.</strong> A spec document with explicit sections (files, changes, dependencies, tests) loses less information than a paragraph of prose. Structure forces completeness.</p><p><strong>3. Prefer isolated contexts to reduce cross-contamination.</strong> When Agent A&#39;s exploration context leaks into Agent B&#39;s execution context, Agent B has less room for its own work and may be distracted by irrelevant details.</p><p><strong>4. Put expensive exploration in sub-agents to protect main context.</strong> The main context is the most valuable resource — it carries the conversation with the user and the high-level task understanding. Protect it aggressively.</p><p><strong>5. Design clear boundaries between agent responsibilities.</strong> Ambiguous boundaries lead to duplicated work or gaps. Each agent should have a well-defined input, process, and output.</p><p><strong>6. Monitor total cost — spawning agents is not free.</strong> The token savings from multi-agent are real but not automatic. Track spawning overhead and ensure each sub-agent justifies its cost.</p><p><strong>7. Design for sub-agent failure.</strong> Sub-agents can fail, produce poor results, or misunderstand their tasks. The orchestrator must be able to detect failures and retry or compensate.</p><p><strong>8. Batch related exploration into single sub-agents.</strong> Spawning 5 sub-agents to read 5 related files is less efficient than spawning 1 sub-agent to read all 5 and synthesize the results.</p><hr><h2 id="_13-comparison-table" tabindex="-1">13. Comparison Table <a class="header-anchor" href="#_13-comparison-table" aria-label="Permalink to &quot;13. Comparison Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>System</th><th>Architecture</th><th># Agents</th><th>Handoff Type</th><th>Isolation Level</th><th>Token Savings Claim</th></tr></thead><tbody><tr><td>Claude Code</td><td>Orchestrator + Workers</td><td>Dynamic</td><td>Summary</td><td>Fully isolated</td><td>~70-90% (estimated)</td></tr><tr><td>ForgeCode</td><td>3-Stage Pipeline</td><td>3</td><td>Progressive refine</td><td>Stage-isolated</td><td>Up to 93%</td></tr><tr><td>Ante</td><td>Meta + Sub-agents</td><td>Dynamic</td><td>Summary</td><td>Fully isolated</td><td>Scales with agents</td></tr><tr><td>Capy</td><td>2-Phase (Captain/Build)</td><td>2</td><td>Structured spec</td><td>Phase-isolated</td><td>~60-80% (estimated)</td></tr><tr><td>TongAgents</td><td>Role-specialized</td><td>Variable</td><td>Shared output fmt</td><td>Role-isolated</td><td>Proportional</td></tr><tr><td>OpenHands</td><td>Event-driven</td><td>Variable</td><td>Event stream</td><td>Loosely coupled</td><td>Varies by task</td></tr></tbody></table><h3 id="architecture-trade-offs" tabindex="-1">Architecture Trade-offs <a class="header-anchor" href="#architecture-trade-offs" aria-label="Permalink to &quot;Architecture Trade-offs&quot;">​</a></h3>`,57)),(s(),i(l,null,{default:n(()=>[r(o,{id:"mermaid-865",class:"mermaid",graph:"quadrantChart%0A%20%20%20%20title%20Flexibility%20vs%20Structure%0A%20%20%20%20x-axis%20loose%20--%3E%20rigid%0A%20%20%20%20y-axis%20low%20flexibility%20--%3E%20high%20flexibility%0A%20%20%20%20Claude%20Code%3A%20%5B0.25%2C%200.65%5D%0A%20%20%20%20ForgeCode%3A%20%5B0.85%2C%200.25%5D%0A%20%20%20%20Ante%3A%20%5B0.15%2C%200.85%5D%0A%20%20%20%20TongAgents%3A%20%5B0.75%2C%200.85%5D%0A%20%20%20%20Capy%3A%20%5B0.25%2C%200.35%5D%0A%20%20%20%20OpenHands%3A%20%5B0.75%2C%200.55%5D%0A"})]),fallback:n(()=>[...e[11]||(e[11]=[a(" Loading... ",-1)])]),_:1})),e[39]||(e[39]=t("p",null,[t("strong",null,"Choosing the right architecture depends on the task:")],-1)),e[40]||(e[40]=t("ul",null,[t("li",null,"Fixed, well-understood workflows → Pipeline (ForgeCode)"),t("li",null,"Variable, exploratory tasks → Dynamic spawning (Claude Code, Ante)"),t("li",null,"Tasks requiring audit trails → Event stream (OpenHands)"),t("li",null,"Tasks with clear planning/execution split → Two-phase (Capy)"),t("li",null,"Tasks with diverse subtask types → Role-specialized (TongAgents)")],-1)),e[41]||(e[41]=t("p",null,"The multi-agent approach to context management transforms the fundamental constraint of LLM systems. Instead of fighting to fit everything into one window, it embraces distribution — giving each piece of work the clean, focused context it deserves, and keeping the orchestrator's view high-level and manageable. The cost is complexity and coordination overhead, but for any task beyond trivial complexity, the token savings and context quality improvements make multi-agent the dominant strategy.",-1))])}const x=d(g,[["render",h]]);export{C as __pageData,x as default};
